# verify-agent-supplier-3-2-FINAL.ps1 (pure ASCII source, BOM only)
# Final full 30-utterance verification with every fix from this session
# combined: UTF-8-safe request/response I/O (Invoke-WebRequest + explicit
# byte-level UTF-8 encode/decode), iFieldsBlock matching production format
# exactly (json-fenced code block, 'my industry info' header), the
# realtimeDisclosurePreamble included (with an explicit test-environment
# verified=true note), and AGENT-SUPPLIER-COMMON v2.2 (strengthened
# section 3-2 wording, 'does not stop at the offer').

$ErrorActionPreference = 'Stop'
try { [Console]::OutputEncoding = [System.Text.Encoding]::UTF8 } catch {}
function _b64d($s) { [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($s)) }

$startMsgB64 = "RklOQUwgdmVyaWZpY2F0aW9uIC0gYWxsIGZpeGVzIGNvbWJpbmVkIChVVEYtOC1zYWZlIEkvTywgY29ycmVjdCBpRmllbGRzQmxvY2ssIHJlYWx0aW1lRGlzY2xvc3VyZVByZWFtYmxlLCBBR0VOVC1TVVBQTElFUi1DT01NT04gdjIuMikgLSAzMCB1dHRlcmFuY2Vz"
$workerUrlLabelB64 = "V29ya2VyIFVSTCAoZGVmYXVsdDogaHR0cHM6Ly9ob25kaS1wcm94eS50ZW5zb3ItY2l0eS53b3JrZXJzLmRldik6IA=="
$sendingPrefixB64 = "U2VuZGluZyAj"
$savedPrefixB64 = "U2F2ZWQ6IA=="
$errorPrefixB64 = "RVJST1Igb24gIw=="
$doneMsgB64 = "RG9uZS4gUmV2aWV3IHRoZSBvdXRwdXQgZm9sZGVyIGZvciBhbGwgMzAgcmVzcG9uc2VzIHBsdXMgYSBzdW1tYXJ5IGluZGV4Lg=="
$heuristicHeaderB64 = "SGV1cmlzdGljIGF1dG8tZmxhZ3MgKGluZm9ybWF0aW9uYWwgb25seSAtIGFsd2F5cyByZWFkIHRoZSBhY3R1YWwgcmVzcG9uc2UgdGV4dCk6"
$apologyPatternB64 = "Xijso4TshqF87JWI7YOA6rmd6rKM64+EfOyVhOyJveqyjOuPhCk="

$startMsg = _b64d $startMsgB64
$workerUrlLabel = _b64d $workerUrlLabelB64
$sendingPrefix = _b64d $sendingPrefixB64
$savedPrefix = _b64d $savedPrefixB64
$errorPrefix = _b64d $errorPrefixB64
$doneMsg = _b64d $doneMsgB64
$heuristicHeader = _b64d $heuristicHeaderB64
$apologyPattern = _b64d $apologyPatternB64

$agencyPromptB64 = ""
$agencyPrompt = _b64d $agencyPromptB64

$utterancesB64 = ""
$utterances = (_b64d $utterancesB64) | ConvertFrom-Json

Write-Host $startMsg
$WORKER_URL = Read-Host $workerUrlLabel
if ([string]::IsNullOrWhiteSpace($WORKER_URL)) { $WORKER_URL = "https://hondi-proxy.tensor-city.workers.dev" }
$outDir = ".\verify-3-2-FINAL"
New-Item -ItemType Directory -Path $outDir -Force | Out-Null

function Invoke-Utf8Post($uri, $bodyObj) {
  $bodyJson = $bodyObj | ConvertTo-Json -Depth 6
  $bodyBytes = [System.Text.Encoding]::UTF8.GetBytes($bodyJson)
  $webResponse = Invoke-WebRequest -Uri $uri -Method Post -Body $bodyBytes -ContentType "application/json; charset=utf-8" -UseBasicParsing
  try { $rawBytes = $webResponse.RawContentStream.ToArray() }
  catch { $rawBytes = [System.Text.Encoding]::GetEncoding('ISO-8859-1').GetBytes($webResponse.Content) }
  $jsonText = [System.Text.Encoding]::UTF8.GetString($rawBytes)
  return $jsonText | ConvertFrom-Json
}

$summary = @()
$i = 0
foreach ($u in $utterances) {
  $i++
  $group = $u[0]; $text = $u[1]
  Write-Host "$sendingPrefix$i/30 [$group] $text"
  $bodyObj = @{
    guid = "test-guid-final30"
    business_id = "test-biz-conbini-final"
    agencyPrompt = $agencyPrompt
    messages = @(@{ role = "user"; content = $text })
    tier = "biz-flash"
  }
  try {
    $res = Invoke-Utf8Post -uri "$WORKER_URL/business/relay" -bodyObj $bodyObj
    $content = $res.choices[0].message.content
    $hasSpDraft = $content -match '\[SP_DRAFT_REQUEST'
    $hasApologyOpener = $content -match $apologyPattern
    $hasFollowupQ = $content -match '\?'
    $fname = Join-Path $outDir ("{0:D2}_{1}.txt" -f $i, $group)
    $fileBody = "GROUP: $group`nUTTERANCE: $text`n`n--- RESPONSE ---`n$content`n`n--- HEURISTIC FLAGS (informational only) ---`nSP_DRAFT_REQUEST tag present: $hasSpDraft`nStarts with apology word: $hasApologyOpener`nContains a question mark anywhere: $hasFollowupQ"
    [System.IO.File]::WriteAllText((Join-Path (Get-Location) $fname), $fileBody, (New-Object System.Text.UTF8Encoding($false)))
    Write-Host "$savedPrefix$fname"
    $summary += [PSCustomObject]@{ No=$i; Group=$group; Utterance=$text; SP_DRAFT=$hasSpDraft; ApologyOpener=$hasApologyOpener; HasQuestion=$hasFollowupQ }
  } catch {
    Write-Warning "$errorPrefix$i : $($_.Exception.Message)"
    $summary += [PSCustomObject]@{ No=$i; Group=$group; Utterance=$text; SP_DRAFT="ERROR"; ApologyOpener="ERROR"; HasQuestion="ERROR" }
  }
  Start-Sleep -Milliseconds 400
}

$summary | Export-Csv -Path (Join-Path $outDir "summary.csv") -NoTypeInformation -Encoding UTF8
Write-Host $heuristicHeader
$summary | Format-Table -AutoSize
Write-Host $doneMsg
